"use client";
import { useEffect, useState, useRef } from "react";
import { createClient } from "@supabase/supabase-js";
import useDebounce from "@/hooks/useDebounce";

const supabase = createClient(
  process.env.NEXT_PUBLIC_SUPABASE_URL!,
  process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
);

export default function DealsList({
  selectedStore,
  selectedCategory,
    selectedHoliday,
  showHotDeals = false,
  onSelectDeal,
  searchQuery,
  }: any) {

  const [deals, setDeals] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const debouncedSearch = useDebounce(searchQuery, 300);


  // ✅ Unified fetch function
  const fetchDeals = async () => {
    let query = supabase
      .from("deals")
      .select("*")
      .eq("status", "Published")
      .order("published_at", { ascending: false });

    if (selectedStore && selectedStore !== "Recent Deals") {
      query = query.ilike("store_name", `%${selectedStore}%`);
    }

    if (selectedCategory && selectedCategory !== "") {
      query = query.ilike("category", `%${selectedCategory}%`);
    }
	

    const { data, error } = await query;
    if (error) console.error("Error fetching deals:", error.message);
    else setDeals(data || []);

    setLoading(false);
  };

  // ✅ Load deals on filter change
 useEffect(() => {
  const fetchDeals = async () => {
	   setLoading(true); //new line
    let query = supabase
      .from("deals")
      .select("*")
      .eq("status", "Published")
      .order("published_at", { ascending: false });

    // 🏬 CASE 1: Store selected and NOT "Recent Deals"
    if (selectedStore && selectedStore !== "Recent Deals") {
      query = query.ilike("store_name", `%${selectedStore}%`);

      // 🧺 CASE 3: If category ALSO selected, narrow within that store
      if (selectedCategory && selectedCategory !== "") {
        query = query.ilike("category", `%${selectedCategory}%`);
      }
    }
	
	 if (selectedHoliday) {
      query = query.eq("holiday_tag", selectedHoliday); // 👈 filter by event
    }
	
	
	if (showHotDeals) {
  query = query.gte("percent_diff", 30); // adjust threshold
}


if (debouncedSearch) {
  query = query.or(
    `description.ilike.%${debouncedSearch}%,store_name.ilike.%${debouncedSearch}%,category.ilike.%${debouncedSearch}%`
  );
} else {
  // only apply filters when NOT searching
  if (selectedStore && selectedStore !== "Recent Deals")
    query = query.ilike("store_name", `%${selectedStore}%`);

  if (selectedCategory)
    query = query.ilike("category", `%${selectedCategory}%`);

  if (showHotDeals)
    query = query.gte("percent_diff", 50);
}





//if (searchQuery) {
  //    query = query.ilike("description", `%${searchQuery}%`);
    //}
	
    // 🧺 CASE 2: No store (Recent Deals) but category selected
   // else if (selectedCategory && selectedCategory !== "") {
     // query = query.ilike("category", `%${selectedCategory}%`);
   // }

    const { data, error } = await query;

    if (error) {
      console.error("Error fetching deals:", error.message);
    } else {
      setDeals(data || []);
    }

    setLoading(false);
  };

  fetchDeals();
}, [selectedStore, selectedCategory,selectedHoliday, showHotDeals, debouncedSearch]);


  // ✅ Mobile Pull-to-refresh gesture
  useEffect(() => {
    const div = containerRef.current;
    if (!div) return;

    let startY = 0;
    let isPulling = false;

    const onTouchStart = (e: TouchEvent) => {
      if (div.scrollTop === 0) {
        startY = e.touches[0].clientY;
        isPulling = true;
      }
    };

    const onTouchMove = (e: TouchEvent) => {
      if (!isPulling) return;
      const deltaY = e.touches[0].clientY - startY;
      if (deltaY > 70 && !refreshing) {
        setRefreshing(true);
        fetchDeals().then(() => setTimeout(() => setRefreshing(false), 600));
        isPulling = false;
      }
    };

    const onTouchEnd = () => (isPulling = false);

    div.addEventListener("touchstart", onTouchStart, { passive: true });
    div.addEventListener("touchmove", onTouchMove, { passive: true });
    div.addEventListener("touchend", onTouchEnd, { passive: true });

    return () => {
      div.removeEventListener("touchstart", onTouchStart);
      div.removeEventListener("touchmove", onTouchMove);
      div.removeEventListener("touchend", onTouchEnd);
    };
  }, [selectedStore, selectedCategory, refreshing]);

  // ✅ UI rendering
  if (loading)
    return <p className="text-center text-gray-500 mt-10">Loading deals...</p>;
  if (!deals.length)
    return <p className="text-center text-gray-500 mt-10">No deals found.</p>;

  return (
    <div
      ref={containerRef}
      className="flex flex-col divide-y divide-gray-200 overflow-y-auto h-full custom-scroll scroll-smooth"
      style={{ WebkitOverflowScrolling: "touch" }} // ✅ smooth iOS scroll
    >
      {refreshing && (
        <div className="text-center text-gray-500 text-sm py-2">
          Refreshing...
        </div>
      )}

      {deals.map((deal) => (
        <div
          key={deal.id}
          onClick={() => onSelectDeal && onSelectDeal(deal)}
          className="flex items-center gap-4 p-3 h-32 hover:bg-gray-100 cursor-pointer transition"
        >
          {/* Thumbnail */}
          <div className="w-20 h-20 flex-shrink-0 bg-gray-100 rounded-md overflow-hidden">
            {deal.image_link ? (
              <img
                src={deal.image_link}
                alt={deal.description}
                className="w-full h-full object-contain bg-white"
              />
            ) : (
              <div className="w-full h-full flex items-center justify-center text-gray-400 text-xs">
                No Image
              </div>
            )}
          </div>

          {/* Info */}
          <div className="flex-1 min-w-0">
            <div className="flex justify-between items-center">
              <h3 className="font-semibold text-gray-800 line-clamp-2 leading-snug">
                {deal.description || "Untitled deal"}
              </h3>
              {deal.percent_diff ? (
                <span className="text-sm text-green-600 font-bold ml-2">
                  -{deal.percent_diff.toFixed(0)}%
                </span>
              ) : null}
            </div>
            <p className="text-sm text-gray-500 truncate">
              {deal.store_name || "Unknown store"}
            </p>
            <div className="text-sm text-gray-600 mt-1">
              {deal.current_price ? (
                <span className="font-semibold text-green-600">
                  ${deal.current_price.toFixed(2)}
                </span>
              ) : null}
              {deal.old_price ? (
                <span className="ml-2 line-through text-gray-400">
                  ${deal.old_price.toFixed(2)}
                </span>
              ) : null}
            </div>
          </div>
        </div>
      ))}
    </div>
  );
}
